@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Authorize(Roles = "Dispatcher")]

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>

<div class="mb-3 row">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="destinationFilter" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-primary" @onclick="LoadShipments">Refresh</button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match the current filters.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>ETA</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string destinationFilter = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(destinationFilter) ||
             s.Destination.Contains(destinationFilter, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) ||
             s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Authorize]

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                }
                else
                {
                    <span>Search</span>
                }
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Tracking #: @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>

            <div class="mt-3">
                <h6>Delivery Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercent(shipment.Status)%"
                         aria-valuenow="@GetProgressPercent(shipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;
    private bool isSearching;

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searched = true;
        isSearching = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
