using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Controllers;

[ApiController]
[Route("api/shipments")]
[Authorize]
public class ShipmentsController : ControllerBase
{
    private readonly ApplicationDbContext _db;

    public ShipmentsController(ApplicationDbContext db)
    {
        _db = db;
    }

    [HttpGet]
    [Authorize(Roles = "Dispatcher")]
    public async Task<ActionResult<List<ShipmentEntity>>> GetAll()
    {
        var shipments = await _db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
        return Ok(shipments.Select(ToDto).ToList());
    }

    [HttpGet("track/{trackingNumber}")]
    public async Task<ActionResult<Shipment>> GetByTracking(string trackingNumber)
    {
        var entity = await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        if (entity is null) return NotFound();
        return Ok(ToDto(entity));
    }

    [HttpGet("customer/{email}")]
    public async Task<ActionResult<List<Shipment>>> GetByCustomer(string email)
    {
        var shipments = await _db.Shipments
            .Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.ShippedDate)
            .ToListAsync();
        return Ok(shipments.Select(ToDto).ToList());
    }

    [HttpPut("{id}/status")]
    [Authorize(Roles = "Dispatcher")]
    public async Task<IActionResult> UpdateStatus(int id, [FromBody] ShipmentStatus status)
    {
        var entity = await _db.Shipments.FindAsync(id);
        if (entity is null) return NotFound();
        entity.Status = status;
        await _db.SaveChangesAsync();
        return NoContent();
    }

    private static Shipment ToDto(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        ShippedDate = e.ShippedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description
    };
}

